// SPX intraday expected-move cone.
//
// Phase-5 model (calibrated + OOS-validated on 771 RTH days 2023-05..2026-06 and
// real 0DTE option data 2024-01..2026-04 — see `AI STUFF/analysis/expected_move_cone/`
// JOURNAL.md Phase 5, harness `phase5_calibrate.py`):
//
//   half_side(k, elapsed) = M_side(k) * S_close * sqrt(varianceShare(anchor, elapsed))
//
// 1. ACCRUAL — intraday variance does NOT accrue linearly in clock time (the open is
//    ~2.5x hotter per minute than lunch). `CONE_VARIANCE_CUM` is the measured cumulative
//    variance share by minute-of-session; the old linear-sqrt(t) cone was ~25% too narrow
//    (in variance) anchored at the open and ~15-25% too wide midday.
// 2. SCALE — per-day implied scale from the live 0DTE credits (kind:"implied") is the
//    best available predictor of the remaining session (Spearman 0.88 vs realized; the
//    first-30-min-RV proxy manages 0.75, a static prior 0.60). Fallback: the per-time-of-
//    day prior measured in Phase 0 (kind:"prior").
// 3. CALIBRATION — credit-implied scales carry a variance risk premium (~6% wide) and the
//    realized distribution is crash-skewed (left tail fat, right tail thin). For the
//    implied kind each level k maps to per-side multipliers M_dn/M_up = bias x empirical
//    z-quantile (train <= 2025-09-30; held OOS 2025-10..2026-06: 1.645-sigma band covers
//    ~90% with balanced ~5%/5% breaches, vs 85-89% down-heavy for the old model).
//    The prior kind keeps symmetric Gaussian k — median-|z| bias correction is WRONG for
//    an unconditional scale (it recentres on the median day and abandons the tails).
//
// Levels: 1, 1.645 (the ~0.05-delta short-strike "frontier"), 2 — these are the chart's
// level KEYS; the implied kind's actual half-widths apply the calibrated multipliers.

import { DEFAULT_WIDTH, impliedScale, signedDistanceToLoss, type SpreadSide } from "./spreadResponse";

export const CONE_DEFAULT_LEVELS = [1, 1.645, 2] as const;
// Measured global diffusion coefficient (pts/sqrt-min), 745 days 2023-05 .. 2026-05.
export const CONE_PRIOR_A = 2.1;
// Per-time-of-day A keyed by minutes-to-close (16:00 ET). The open is the hottest part of
// the session; the prior interpolates this curve. From backtest_cone.py (Phase 0).
const PRIOR_A_BY_MTC: ReadonlyArray<readonly [number, number]> = [
  [60, 1.87], // 15:00
  [120, 1.75], // 14:00
  [180, 2.14], // 13:00
  [240, 1.94], // 12:00
  [300, 2.02], // 11:00
  [360, 2.19], // 10:00
  [390, 2.38], // 09:30
];

