// Per-side level multipliers for the IMPLIED scale kind (= bias x empirical z-quantile):
// variance-risk-premium correction + crash skew in one step. Keys match CONE_DEFAULT_LEVELS.
const CONE_IMPLIED_K_DOWN: ReadonlyMap<number, number> = new Map([
  [1, 0.8454],
  [1.645, 1.6868],
  [2, 2.1802],
]);
const CONE_IMPLIED_K_UP: ReadonlyMap<number, number> = new Map([
  [1, 0.9649],
  [1.645, 1.595],
  [2, 1.8427],
]);

export type ConeScale =
  | { kind: "implied"; s0: number; sourceMinutesToClose: number } // day move-scale at the anchor (index pts)
  | { kind: "prior"; a?: number }; // a defaults to the time-of-day prior

export type ConeLevelPoint = {
  minutesToClose: number;
  elapsedMinutes: number;
  upper: number;
  lower: number;
  half: number; // mean of the two side half-widths (kept for back-compat)
  halfUp: number;
  halfDown: number;
};

export type ConeLevel = { k: number; points: ConeLevelPoint[] };

export type ExpectedMoveCone = {
  anchorSpot: number;
  anchorMinutesToClose: number;
  rate: number; // S_close / sqrt(mtc) — kept for back-compat with the old linear model
  scaleKind: "implied" | "prior";
  sAtClose: number; // 1-sigma scale at 16:00 (pre-multiplier)
  closeRange: { upper: number; lower: number; half: number }; // k=1 band at the close
  levels: ConeLevel[];
};

/** Time-of-day prior rate r (pts/sqrt-min) by minutes-to-close, interpolated + clamped. */
export function priorRate(minutesToClose: number): number {
  const mtc = Math.max(minutesToClose, 0);
  const t = PRIOR_A_BY_MTC;
  if (mtc <= t[0][0]) return t[0][1];
  if (mtc >= t[t.length - 1][0]) return t[t.length - 1][1];
  for (let i = 1; i < t.length; i++) {
    if (mtc <= t[i][0]) {
      const [m0, a0] = t[i - 1];
      const [m1, a1] = t[i];
      return a0 + ((a1 - a0) * (mtc - m0)) / (m1 - m0);
    }
  }
  return CONE_PRIOR_A;
}

/** Linear interpolation into CONE_VARIANCE_CUM at a fractional session-minute index. */
function varianceCumAt(index: number): number {
  const last = CONE_VARIANCE_CUM.length - 1;
  const x = Math.min(Math.max(index, 0), last);
  const i = Math.floor(x);
  if (i >= last) return CONE_VARIANCE_CUM[last];
  const frac = x - i;
  return CONE_VARIANCE_CUM[i] + (CONE_VARIANCE_CUM[i + 1] - CONE_VARIANCE_CUM[i]) * frac;
}

/**
 * Share of the anchor->close variance realized `elapsed` minutes after an anchor placed
 * `anchorMinutesToClose` before the close. 0 at the anchor, 1 at the close. Uses the
 * measured intraday profile for a regular 390-minute session; falls back to linear
 * accrual for other session lengths (half-days) where the profile was not fit.
 *
 * Anchors EARLIER than the profiled session (mtc > 389, e.g. a 09:30:00 wall clock or
 * pre-market) clamp to the open: the share stays 0 until the elapsed grid reaches the
 * open, then accrues on the profile. That is the correct RTH-only semantics — the chart
 * and the profile both cover 09:30-16:00, and no RTH variance accrues before the open.
 */
export function varianceShare(anchorMinutesToClose: number, elapsed: number, sessionMinutes: number = CONE_SESSION_MINUTES): number {
  const mtc = Math.max(anchorMinutesToClose, 0);
  const e = Math.min(Math.max(elapsed, 0), mtc);
  if (mtc <= 0) return 0;
  if (sessionMinutes !== CONE_SESSION_MINUTES) {
    return e / mtc; // unprofiled session shape — honest linear fallback
  }
  const last = CONE_VARIANCE_CUM.length - 1; // = close index
  const anchorIdx = last - mtc;
  const wAnchor = varianceCumAt(anchorIdx);
  const denom = CONE_VARIANCE_CUM[last] - wAnchor;
  if (denom <= 0) return e >= mtc ? 1 : 0;
  return (varianceCumAt(anchorIdx + e) - wAnchor) / denom;
}

function impliedSideK(level: number, side: "up" | "down"): number {
  const table = side === "up" ? CONE_IMPLIED_K_UP : CONE_IMPLIED_K_DOWN;
  // Uncalibrated custom levels degrade to the symmetric Gaussian k.
  return table.get(level) ?? level;
}

/** 1-sigma scale to the close (index pts) for the given anchor, before level multipliers. */
function scaleAtClose(scale: ConeScale, anchorMinutesToClose: number, sessionMinutes: number): number {
  const mtc = Math.max(anchorMinutesToClose, 0);
  if (scale.kind === "implied") {
    const src = Math.max(scale.sourceMinutesToClose, 0.5);
    if (Number.isFinite(scale.s0) && scale.s0 > 0) {
      if (Math.abs(src - mtc) < 1e-9) return scale.s0;
      // Re-anchor an implied scale quoted at a different horizon through the profile:
      // remaining-variance ratio between the two anchors.
      const last = CONE_VARIANCE_CUM.length - 1;
      const rem = (m: number) => Math.max(CONE_VARIANCE_CUM[last] - varianceCumAt(last - Math.max(m, 0)), 0);
      const ratio = sessionMinutes === CONE_SESSION_MINUTES && rem(src) > 0 ? rem(mtc) / rem(src) : mtc / src;
      return scale.s0 * Math.sqrt(Math.max(ratio, 0));
    }
    return priorRate(mtc) * Math.sqrt(mtc);
  }
  const a = scale.a != null && scale.a > 0 ? scale.a : priorRate(mtc);
  return a * Math.sqrt(mtc);
}

/**
 * Build the expected-move cone from an anchor (spot + minutes-to-close) and a scale.
 * Points run from the anchor (elapsed 0, half 0) forward to the close on a `stepMinutes`
 * grid. Pure / time-agnostic — the chart layer maps each point's elapsed to a bar epoch.
 */
export function expectedMoveCone(input: {
  anchorSpot: number;
  anchorMinutesToClose: number;
  scale: ConeScale;
  levels?: number[];
  stepMinutes?: number;
  sessionMinutes?: number;
}): ExpectedMoveCone {
  const mtc = Math.max(input.anchorMinutesToClose, 0);
  const step = Math.max(input.stepMinutes ?? 2, 0.5);
  const session = input.sessionMinutes ?? CONE_SESSION_MINUTES;
  const levels = (input.levels ?? [...CONE_DEFAULT_LEVELS]).slice().sort((a, b) => a - b);
  const sClose = scaleAtClose(input.scale, mtc, session);
  const implied = input.scale.kind === "implied" && Number.isFinite((input.scale as { s0?: number }).s0 ?? Number.NaN) && (input.scale as { s0: number }).s0 > 0;

  // Forward elapsed grid: 0, step, 2*step, ..., mtc (always include the close endpoint).
  const elapsedGrid: number[] = [];
  for (let e = 0; e < mtc; e += step) elapsedGrid.push(e);
  elapsedGrid.push(mtc);

  const coneLevels: ConeLevel[] = levels.map((k) => {
    const kUp = implied ? impliedSideK(k, "up") : k;
    const kDown = implied ? impliedSideK(k, "down") : k;
    return {
      k,
      points: elapsedGrid.map((elapsed) => {
        const sqrtShare = Math.sqrt(varianceShare(mtc, elapsed, session));
        const halfUp = kUp * sClose * sqrtShare;
        const halfDown = kDown * sClose * sqrtShare;
        return {
          elapsedMinutes: elapsed,
          minutesToClose: mtc - elapsed,
          half: 0.5 * (halfUp + halfDown),
          halfUp,
          halfDown,
          upper: input.anchorSpot + halfUp,
          lower: input.anchorSpot - halfDown,
        };
      }),
    };
  });

  const k1Up = implied ? impliedSideK(1, "up") : 1;
  const k1Down = implied ? impliedSideK(1, "down") : 1;
  return {
    anchorSpot: input.anchorSpot,
    anchorMinutesToClose: mtc,
    rate: mtc > 0 ? sClose / Math.sqrt(mtc) : 0,
    // Report the kind that actually drove the math: an "implied" ConeScale with a
    // missing/invalid s0 resolves to the prior — the legend must not claim live IV.
    scaleKind: implied ? "implied" : "prior",
    sAtClose: sClose,
    closeRange: {
      half: 0.5 * (k1Up + k1Down) * sClose,
      upper: input.anchorSpot + k1Up * sClose,
      lower: input.anchorSpot - k1Down * sClose,
    },
    levels: coneLevels,
  };
}

// --- derive ONE day move-scale from the live spreads (the per-day cone width) ---

export type ConeSpreadInput = {
  side: SpreadSide;
  shortStrike: number;
  width?: number;
  creditNow?: number | null;
};

function median(xs: number[]): number {
  const s = xs.slice().sort((a, b) => a - b);
  const mid = Math.floor(s.length / 2);
  return s.length % 2 ? s[mid] : 0.5 * (s[mid - 1] + s[mid]);
}

/**
 * Collapse the on-screen 0DTE spreads to one `ConeScale`: the median of each spread's
 * implied move-scale (reuses spreadResponse.impliedScale — the same vol that drives the
 * P/L curve). Median is robust to one mismarked leg. `aPrior` is passed as NaN so the
 * inversion's internal 1.21·sqrt(mtc) fallback can never masquerade as an implied scale —
 * ill-conditioned credits (near 0 / near width / far-ITM) drop out here and we honestly
 * return the `prior` kind when nothing usable remains.
 */
export function coneScaleFromSpreads(
  spreads: ConeSpreadInput[],
  spot: number,
  minutesToClose: number,
): ConeScale {
  const s0s = spreads
    .filter((s) => s.creditNow != null && Number.isFinite(s.creditNow))
    .map((s) =>
      impliedScale(
        s.creditNow as number,
        signedDistanceToLoss(s.side, spot, s.shortStrike),
        s.width ?? DEFAULT_WIDTH,
        minutesToClose,
        Number.NaN,
      ),
    )
    .filter((x) => Number.isFinite(x) && x > 0);
  if (!s0s.length) return { kind: "prior" };
  return { kind: "implied", s0: median(s0s), sourceMinutesToClose: Math.max(minutesToClose, 0.5) };
}
